  ('promotion-7fec267e-moex-00162', 'promotion-7fec267e', 'promotion-7fec267e-moex-110-3082b5f1', 'sub-promotion-7fec267e-04', NULL, 'single_choice', '甲建設公司（以下簡稱甲）向A市工務局申請某建地建築執照獲准後，隨即動工並已接近完工。 但本案經A市工務局的上級機關實施業務督導時，發現甲建地位居建築高度限制區域，要求A市 工務局依法改正。A市工務局據此發函撤銷建照，要求甲重新遞件申請，並將超過限高部分之樓 層拆除。若甲不服提起救濟，得以下列何者據以請求財產損失補償之理由？', '["信賴保護原則", "不當聯結禁止原則", "平等原則", "公益原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:41+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "101", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "一般行政"}'::jsonb, NULL),
  ('promotion-7fec267e-moex-00163', 'promotion-7fec267e', 'promotion-7fec267e-moex-110-3082b5f1', 'sub-promotion-7fec267e-04', NULL, 'single_choice', '下列何者非屬不確定法律概念？', '["申請紓困條件為因受疫情影響而生活陷入困頓者", "對於人民陳情案件，受理機關應以公正積極態度處理之", "對於人民違法排放污染之裁罰，同一法條同一年內有違反並裁罰在案者得加重處罰", "開發行為對於環境生態有重大侵害之虞時，主管機關得命其停工"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:41+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "101", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "一般行政"}'::jsonb, NULL),
  ('promotion-7fec267e-moex-00164', 'promotion-7fec267e', 'promotion-7fec267e-moex-110-3082b5f1', 'sub-promotion-7fec267e-04', NULL, 'single_choice', 'A市環保局審查甲工廠廢水排放許可證有效期間的展延申請，A市環保局要求甲工廠須支付鄰近 里民健康檢查費用，始能通過審查。甲工廠負責人不服提起行政救濟時，得主張A市環保局違反 何種一般行政法原則？', '["比例原則", "不當聯結禁止原則", "信賴保護原則", "平等原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:41+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "101", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "一般行政"}'::jsonb, NULL),
  ('promotion-7fec267e-moex-00165', 'promotion-7fec267e', 'promotion-7fec267e-moex-110-3082b5f1', 'sub-promotion-7fec267e-04', NULL, 'single_choice', '民間團體或個人受託行使公權力所生之法律關係，下列敘述何者錯誤？', '["於受委託之範圍以外，非為行政機關", "於受委託之範圍以外與第三人發生法律關係者，應屬公法關係", "受委託行使公權力之團體，其執行職務之人，視同委託機關之公務員", "於受委託之範圍內，應以該私人或團體的名義作成行政處分"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:41+00:00", "source_pdf_sha1": "e540f9f070e7", "answer_pdf_sha1": "8eeba1fd9cc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110170", "c": "101", "s": "0407", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員升官等考試、110年關務人員升官等考試、110年交通事業公路人員升資考試、110年交通事業港務人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "一般行政"}'::jsonb, NULL),
